namespace sv_63f0da98a4aa4f70bff4e0d242a9ee68.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public DateTimeOffset? EstimatedDelivery { get; init; }
    public required List<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required string Description { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset Timestamp { get; init; }
}

using sv_63f0da98a4aa4f70bff4e0d242a9ee68.Client.Models;

namespace sv_63f0da98a4aa4f70bff4e0d242a9ee68.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_63f0da98a4aa4f70bff4e0d242a9ee68.Client.Models;
using sv_63f0da98a4aa4f70bff4e0d242a9ee68.Client.Services;

namespace sv_63f0da98a4aa4f70bff4e0d242a9ee68.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Memphis, TN",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 25, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Los Angeles, CA", Timestamp = new DateTimeOffset(2026, 5, 20, 10, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Departed facility", Location = "Los Angeles, CA", Timestamp = new DateTimeOffset(2026, 5, 20, 14, 30, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Arrived at hub", Location = "Memphis, TN", Timestamp = new DateTimeOffset(2026, 5, 21, 6, 15, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "In transit to destination", Location = "Memphis, TN", Timestamp = new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero) },
            ]
        },
        ["TRK-002"] = new Shipment
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "New York, NY",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Chicago, IL", Timestamp = new DateTimeOffset(2026, 5, 18, 9, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "In transit", Location = "Columbus, OH", Timestamp = new DateTimeOffset(2026, 5, 19, 11, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Out for delivery", Location = "New York, NY", Timestamp = new DateTimeOffset(2026, 5, 21, 7, 45, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Delivered", Location = "New York, NY", Timestamp = new DateTimeOffset(2026, 5, 21, 11, 30, 0, TimeSpan.Zero) },
            ]
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Seattle, WA", Timestamp = new DateTimeOffset(2026, 5, 22, 14, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Awaiting pickup", Location = "Seattle, WA", Timestamp = new DateTimeOffset(2026, 5, 22, 14, 5, 0, TimeSpan.Zero) },
            ]
        },
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

using System.Net.Http.Json;
using sv_63f0da98a4aa4f70bff4e0d242a9ee68.Client.Models;

namespace sv_63f0da98a4aa4f70bff4e0d242a9ee68.Client.Services;

/// <summary>
/// HTTP-based implementation used when running on WebAssembly.
/// Calls the server API endpoint to retrieve shipment data.
/// </summary>
public sealed class ShipmentHttpService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<Shipment>(ct)
            ?? throw new InvalidOperationException("Received null response from server.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_63f0da98a4aa4f70bff4e0d242a9ee68.Client.Models
@using sv_63f0da98a4aa4f70bff4e0d242a9ee68.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@(_shipment.EstimatedDelivery?.ToString("f") ?? "N/A")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <strong>@update.Timestamp.ToString("g")</strong> —
                    @update.Description (@update.Location)
                </li>
            }
        </ul>
    </div>
}

@code {
    private CancellationTokenSource? _cts;
    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private string? _lastLoadedTrackingNumber;

    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    protected override async Task OnParametersSetAsync()
    {
        // If the tracking number hasn't changed, don't reload
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase) && _shipment is not null)
        {
            return;
        }

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, _cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Request was cancelled (navigation away or new tracking number) — do nothing
            return;
        }
        catch (TaskCanceledException)
        {
            Logger.LogWarning("Request timed out for tracking number {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException)
        {
            Logger.LogWarning("Request timed out for tracking number {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (KeyNotFoundException)
        {
            Logger.LogWarning("Shipment not found: {TrackingNumber}", TrackingNumber);
            _errorMessage = $"Shipment '{TrackingNumber}' was not found.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

